#include <cuda_runtime.h>
#include <cstdio>

__global__ void red_herring(const float* in, float* out, int n) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= n) {
        return;
    }

    if ((blockIdx.x & 1) == 0) {
        __syncthreads();
    }

    int idx = (tid * 131) & (n - 1);
    float x = in[idx];
    float y = in[(idx + 257) & (n - 1)];
    out[tid] = x + y * 0.5f;
}

int main() {
    const int n = 1 << 20;
    const size_t bytes = static_cast<size_t>(n) * sizeof(float);
    float* h = new float[n];
    float *in, *out;
    cudaMalloc(&in, bytes);
    cudaMalloc(&out, bytes);
    for (int i = 0; i < n; ++i) {
        h[i] = static_cast<float>((i * 7) % 193) * 0.02f;
    }
    cudaMemcpy(in, h, bytes, cudaMemcpyHostToDevice);
    red_herring<<<(n + 255) / 256, 256>>>(in, out, n);
    cudaMemcpy(h, out, bytes, cudaMemcpyDeviceToHost);
    std::printf("%f\n", h[2]);
    cudaFree(in);
    cudaFree(out);
    delete[] h;
    return 0;
}

